class Solution {
    public int minimumOperationsToMakeEqual(int x, int y) {
        int diff = Math.abs(x - y);
        int res = diff;
        for (int i = 0; i * 5 <= diff; i++) {
            int temp = diff - i * 5;
            if (temp % 11 == 0) {
                res = Math.min(res, i + temp / 11);
            }
        }
        return res;
    }
}
